    uint32_t kD = static_cast<uint32_t>(w_shape->GetDim(2));
    uint32_t kH = static_cast<uint32_t>(w_shape->GetDim(3));
    uint32_t kW = static_cast<uint32_t>(w_shape->GetDim(4));

    uint32_t D_out = D_in + kD - 1;
    uint32_t H_out = H_in + kH - 1;
    uint32_t W_out = W_in + kW - 1;

    y_shape->SetDimNum(5);
    y_shape->SetDim(0, N);
    y_shape->SetDim(1, static_cast<uint32_t>(w_shape->GetDim(0)));
    y_shape->SetDim(2, D_out);
    y_shape->SetDim(3, H_out);
    y_shape->SetDim(4, W_out);
    return GRAPH_SUCCESS;
}

